import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import SearchBar from '../components/SearchBar.js';
import './css/Recipes.css';

function Recipes({ user }) {
  const [recipes, setRecipes] = useState([]);
  const [filteredRecipes, setFilteredRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchRecipes = async () => {
      if (!user || !(user.id || user._id)) {
        setRecipes([]);
        setFilteredRecipes([]);
        setLoading(false);
        return;
      }
      setLoading(true);
      try {
        const userId = user.id || user._id;
        const response = await fetch(`http://localhost:8000/recipes/user/${userId}`);
        if (response.ok) {
          const data = await response.json();
          setRecipes(data);
          setFilteredRecipes(data);
        } else {
          setRecipes([]);
          setFilteredRecipes([]);
        }
      } catch (err) {
        setRecipes([]);
        setFilteredRecipes([]);
      }
      setLoading(false);
    };
    fetchRecipes();
  }, [user]);

  const handleSearch = (query) => {
    const filtered = recipes.filter((r) =>
      r.recipe_name.toLowerCase().includes(query.toLowerCase())
    );
    setFilteredRecipes(filtered);
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>Recipes</h1>
        <button className="btn-primary" onClick={() => navigate('/recipes/add')}>
          + Add Recipe
        </button>
      </div>

      <SearchBar onSearch={handleSearch} />

      <div className="recipe-grid">
        {loading ? (
          <p className="recipes-empty">Loading...</p>
        ) : filteredRecipes.length === 0 ? (
          <p className="recipes-empty">No recipes yet.</p>
        ) : (
          filteredRecipes.map((recipe, idx) => (
            <div
              className="card recipe-card"
              key={recipe._id || recipe.id || idx}
              onClick={() => navigate(`/recipes/${recipe._id || recipe.id}`)}
            >
              {recipe.image_url && (
                <img className="recipe-card-img" src={recipe.image_url} alt={recipe.recipe_name} />
              )}
              <div className="recipe-card-body">
                <h3 className="recipe-card-title">{recipe.recipe_name}</h3>
                <div className="recipe-card-meta">
                  {recipe.cuisine && <span className="badge">{recipe.cuisine}</span>}
                  {recipe.tags && <span className="badge">{recipe.tags}</span>}
                </div>
                <div className="recipe-card-times">
                  {recipe.prep_time && <span>Prep {recipe.prep_time}m</span>}
                  {recipe.cook_time && <span>Cook {recipe.cook_time}m</span>}
                  {recipe.servings && <span>Serves {recipe.servings}</span>}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default Recipes;
